class Solution(object):
    def longestSubsequence(self, nums):
        n = len(nums)
        total_xor = 0
        for v in nums:
            total_xor ^= v
        # If XOR of entire array is non-zero, answer is n
        if total_xor != 0:
            return n
        # XOR is 0; try removing one element to get non-zero XOR
        # Remove nums[i]: new XOR = total_xor ^ nums[i] = nums[i]
        # Need nums[i] != 0
        for v in nums:
            if v != 0:
                return n - 1
        # All zeros: any subsequence has XOR 0; return 0
        return 0
